@namespace Lumeo
@implements IAsyncDisposable
@inject ComponentInteropService Interop

<span id="@_elementId" class="@CssClass" @attributes="AdditionalAttributes">
    @for (var i = 0; i < _words.Length; i++)
    {
        <span data-motion-word style="transition-delay:@(i * Stagger)ms">@_words[i]</span>
        @if (i < _words.Length - 1)
        {
            @(" ")
        }
    }
</span>

@code {
    /// <summary>The text to reveal, split on whitespace into individually-animated words.</summary>
    [Parameter] public string Text { get; set; } = string.Empty;
    /// <summary>Delay in milliseconds added per word index, so later words reveal after earlier ones. Default 80.</summary>
    [Parameter] public int Stagger { get; set; } = 80;
    /// <summary>Fraction of the element that must be visible in the viewport before the reveal triggers, passed to the underlying <c>IntersectionObserver</c>. Clamped to [0, 1]. Default 0.3.</summary>
    [Parameter] public double Threshold { get; set; } = 0.3;
    /// <summary>Additional CSS classes merged onto the root <c>&lt;span&gt;</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the root <c>&lt;span&gt;</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = $"lumeo-reveal-{Guid.NewGuid():N}";
    private string[] _words = Array.Empty<string>();
    private bool _registered;

    private string CssClass => string.Join(" ", new[] { "lumeo-reveal", Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    protected override void OnParametersSet()
    {
        _words = string.IsNullOrEmpty(Text)
            ? Array.Empty<string>()
            : Text.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_registered)
        {
            _registered = true;
            try
            {
                // Clamp Threshold to the IntersectionObserver-legal [0,1] range before
                // it reaches JS. An out-of-range value (>1 or <0) throws inside
                // `new IntersectionObserver(..., { threshold })`, which left the text
                // permanently invisible and surfaced an unhandled circuit exception.
                // Scoped to the component (not the shared interop service) so the guard
                // doesn't ripple to other MotionRevealText callers.
                await Interop.MotionRevealText(_elementId, Stagger, Math.Clamp(Threshold, 0d, 1d));
            }
            catch (JSDisconnectedException) { }
            catch (JSException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_registered) return;
        try { await Interop.MotionDisposeObserver(_elementId); }
        catch (JSDisconnectedException) { }
    }
}
